CREATE TABLE IF NOT EXISTS purchase_orders(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),warehouse_id uuid NOT NULL REFERENCES warehouses(id)ON DELETE CASCADE,supplier_id uuid NOT NULL REFERENCES partners(id),order_no text NOT NULL,status text NOT NULL DEFAULT'draft'CHECK(status IN('draft','approved','closed','cancelled')),created_by uuid REFERENCES users(id),approved_at timestamptz,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(warehouse_id,order_no));
CREATE TABLE IF NOT EXISTS purchase_order_lines(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),purchase_order_id uuid NOT NULL REFERENCES purchase_orders(id)ON DELETE CASCADE,product_id uuid NOT NULL REFERENCES products(id),ordered_quantity numeric(18,4)NOT NULL CHECK(ordered_quantity>0),received_quantity numeric(18,4)NOT NULL DEFAULT 0 CHECK(received_quantity>=0 AND received_quantity<=ordered_quantity));
CREATE TABLE IF NOT EXISTS purchase_receipt_lines(receipt_document_id uuid NOT NULL REFERENCES stock_documents(id),purchase_order_line_id uuid NOT NULL REFERENCES purchase_order_lines(id),quantity numeric(18,4)NOT NULL CHECK(quantity>0),PRIMARY KEY(receipt_document_id,purchase_order_line_id));
CREATE INDEX IF NOT EXISTS idx_purchase_orders_scope ON purchase_orders(warehouse_id,status,created_at DESC);
